import{_ as e,c as t,o as a,d as s}from"./app.0d14d0b2.js";const f='{"title":"Introduction to Metal","description":"","frontmatter":{"title":"Introduction to Metal","date":"2015-05-02"},"headers":[{"level":2,"title":"DESCRIPTION","slug":"description"},{"level":2,"title":"TOOLS","slug":"tools"},{"level":2,"title":"SKILLS","slug":"skills"},{"level":2,"title":"MATERIALS","slug":"materials"},{"level":2,"title":"MEMBERSHIP","slug":"membership"}],"relativePath":"practice/event/introduction-to-metal/index.md"}',i={},n=s('<h2 id="description" tabindex="-1">DESCRIPTION <a class="header-anchor" href="#description" aria-hidden="true">#</a></h2><p>Interested in making something out of metal? This class seeks to provide you with the fundamental skills and confidence necessary to safely operate within the ADX metal shop, including how to safely clean, cut, drill, grind, form and weld mild steel. You&#39;ll learn how to properly use, care for and setup tools as well as clean up after use. Most importantly, this class gets you on your way to making all that awesome stuff you&#39;ve been day dreaming about! This Introductory class sets the stage for future ADX metal classes, including MIG and TIG welding and various project-based classes.</p><h2 id="tools" tabindex="-1">TOOLS <a class="header-anchor" href="#tools" aria-hidden="true">#</a></h2><p>Plasma cutter, horizontal band saw and abrasive\xA0cut-off saw, drill press and thread tapping machine, grinders and stationary sanders, MIG and spot welders, bench bender, and our sheet metal shear, brake, and slip roll.</p><h2 id="skills" tabindex="-1">SKILL<strong>S</strong> <a class="header-anchor" href="#skills" aria-hidden="true">#</a></h2><p>Measuring, cutting, drilling and countersinking, Forming, grinding and cleaning, clamping,\xA0basic welding.</p><h2 id="materials" tabindex="-1">MATERIALS <a class="header-anchor" href="#materials" aria-hidden="true">#</a></h2><p>ADX provides\xA0Steel stock, all tools and equipment (ticket price includes a $10 Materials fee); you provide\xA0Note taking implements (optional).</p><hr><h2 id="membership" tabindex="-1">MEMBERSHIP <a class="header-anchor" href="#membership" aria-hidden="true">#</a></h2><p>The non-member price includes\xA0<strong>1 month of Unlimited Membership</strong>\xA0so you can practice what you learned and get started on your next project! The month of membership begins the first day of the class; exceptions are politely declined. Before using the shop outside of class time, you must attend one of our free safety orientations.</p>',11),o=[n];function r(l,d,c,h,p,u){return a(),t("div",null,o)}var g=e(i,[["render",r]]);export{f as __pageData,g as default};
